css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #080808; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 76px; border-bottom: 1px solid rgba(255,255,255,0.07); position: sticky; top: 0; background: rgba(8,8,8,0.9); backdrop-filter: blur(20px); z-index: 100; }
.logo { font-size: 22px; font-weight: 900; letter-spacing: 6px; color: #eab308; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.contact-btn { padding: 12px 24px; border-radius: 12px; border: 1px solid #eab308; background: transparent; color: #eab308; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 76px); }
.tag { display: inline-block; color: #eab308; font-size: 13px; font-weight: 700; letter-spacing: 2px; margin-bottom: 20px; }
h1 { font-size: 72px; font-weight: 900; line-height: 1; letter-spacing: -3px; margin-bottom: 20px; } h1 em { font-style: normal; color: #eab308; }
.hero-text p { color: #6b7280; font-size: 17px; line-height: 1.7; margin-bottom: 32px; max-width: 420px; }
.hero-btns { display: flex; gap: 14px; }
.btn-main { padding: 16px 32px; border-radius: 14px; border: none; background: #eab308; color: #080808; font-weight: 800; font-size: 15px; cursor: pointer; }
.btn-outline { padding: 16px 28px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; font-size: 15px; cursor: pointer; }
.gp-grid { display: grid; grid-template-columns: 1fr 1fr; grid-template-rows: auto auto; gap: 12px; }
.gp-item { border-radius: 16px; display: flex; align-items: center; justify-content: center; font-size: 48px; min-height: 150px; } .gp-item.tall { grid-row: span 2; min-height: 312px; } .gp-item.wide { grid-column: span 2; }
.gallery { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.07); }
.gallery-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 32px; }
.gallery-header h2 { font-size: 42px; font-weight: 800; }
.gallery-filters { display: flex; gap: 8px; }
.gf { padding: 10px 20px; border-radius: 20px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: #6b7280; font-size: 13px; font-weight: 600; cursor: pointer; } .gf.active { background: #eab308; border-color: #eab308; color: #080808; }
.masonry { columns: 4; gap: 12px; }
.m-item { break-inside: avoid; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 48px; margin-bottom: 12px; cursor: pointer; transition: transform 0.3s; } .m-item:hover { transform: scale(1.02); }
.services { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.07); }
.services h2 { font-size: 42px; font-weight: 800; margin-bottom: 36px; }
.services-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; }
.service-card { padding: 28px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); } .sc-icon { font-size: 32px; margin-bottom: 14px; } .service-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 8px; } .service-card p { color: #6b7280; font-size: 14px; line-height: 1.6; margin-bottom: 16px; } .service-card strong { color: #eab308; font-size: 16px; }
